import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat result = original.withFirstRecordAsHeader();

        assertNotNull(result, "Result should not be null");
        // withFirstRecordAsHeader returns withHeader().withSkipHeaderRecord()
        // Check that header is set (not null)
        assertNotNull(result.getHeader(), "Header should not be null");
        // Check that skipHeaderRecord is true
        assertTrue(result.getSkipHeaderRecord(), "skipHeaderRecord should be true");
        // The original CSVFormat should remain unchanged
        assertNull(original.getHeader(), "Original header should be null");
        assertFalse(original.getSkipHeaderRecord(), "Original skipHeaderRecord should be false");
    }
}
